// ============================================================================
// Helper traits and utilities
// ============================================================================

namespace detail {

/**
 * @brief Check if a type is an integer type (signed or unsigned)
 */
template<typename T>
using is_integer = std::is_integral<T>;

/**
 * @brief Check if a type is a floating point type
 */
template<typename T>
using is_float = std::is_floating_point<T>;

/**
 * @brief Check if a type is a bit string type (BYTE, WORD, DWORD, LWORD)
 */
template<typename T>
struct is_bitstring : std::false_type
{};

template<>
struct is_bitstring<BYTE> : std::true_type
{};

template<>
struct is_bitstring<WORD> : std::true_type
{};

template<>
struct is_bitstring<DWORD> : std::true_type
{};

template<>
struct is_bitstring<LWORD> : std::true_type
{};

/**
 * @brief Get the bit width of a type
 */
template<typename T>
struct bit_width;

template<>
struct bit_width<BYTE> : std::integral_constant<int, 8>
{};
template<>
struct bit_width<WORD> : std::integral_constant<int, 16>
{};
template<>
struct bit_width<DWORD> : std::integral_constant<int, 32>
{};
template<>
struct bit_width<LWORD> : std::integral_constant<int, 64>
{};

/**
 * @brief Get the bit mask for a type (all bits set)
 */
template<typename T>
inline T allBits()
{
   return static_cast<T>(~static_cast<T>(0));
}

/**
 * @brief Get the sign bit mask for a signed integer type
 */
template<typename T>
inline T signBit()
{
   return static_cast<T>(static_cast<typename std::make_unsigned<T>::type>(1) << (sizeof(T) * 8 - 1));
}

} // namespace detail

// ============================================================================
// Absolute value
// ============================================================================

/**
 * @brief Absolute value
 * 
 * IEC 61131-3: ABS(x)
 * Returns the absolute value of x.
 * For signed integers, ABS(MIN) is undefined (wraps to MIN).
 */
template<typename T>
inline T ABS(T x)
{
   if constexpr (detail::is_float<T>::value) {
      return std::abs(x);
   } else if constexpr (std::is_unsigned<T>::value) {
      return x;
   } else {
      return x < 0 ? -x : x;
   }
}

// Overload for LREAL (Double)
inline LREAL ABS(LREAL x)
{
   return std::abs(x);
}

// ============================================================================
// Square root
// ============================================================================

/**
 * @brief Square root
 * 
 * IEC 61131-3: SQRT(x)
 * Returns the square root of x. x must be non-negative.
 */
template<typename T>
inline T SQRT(T x)
{
   static_assert(detail::is_float<T>::value || std::is_same<T, LREAL>::value, "SQRT is only defined for floating point types");
   return std::sqrt(x);
}

inline LREAL SQRT(LREAL x)
{
   return std::sqrt(x);
}

