// ============================================================================
// Bit shift operations
// ============================================================================

/**
 * @brief Shift left
 * 
 * IEC 61131-3: SHL(x, n)
 * Shifts x left by n bits. The result is modulo 2^bit_width.
 * For bit strings, the shift count is interpreted modulo the bit width.
 */
template<typename T>
inline T SHL(T x, int n)
{
   static_assert(detail::is_bitstring<T>::value, "SHL is only defined for bit string types (BYTE, WORD, DWORD, LWORD)");
   constexpr int width = detail::bit_width<T>::value;
   n = n % width;
   return static_cast<T>((static_cast<typename std::make_unsigned<T>::type>(x) << n) & detail::allBits<T>());
}

// Overload for UInt types (unsigned integers)
template<typename T>
inline T SHL_INT(T x, int n)
{
   static_assert(std::is_unsigned<T>::value, "SHL_INT is only defined for unsigned integer types");
   constexpr int width = sizeof(T) * 8;
   n = n % width;
   if (n >= width) {
      return 0;
   }
   return static_cast<T>(x << n);
}

// ============================================================================
// Shift right (logical)
// ============================================================================

/**
 * @brief Shift right (logical)
 * 
 * IEC 61131-3: SHR(x, n)
 * Shifts x right by n bits (logical shift, zero-fill).
 * For bit strings, the shift count is interpreted modulo the bit width.
 */
template<typename T>
inline T SHR(T x, int n)
{
   static_assert(detail::is_bitstring<T>::value, "SHR is only defined for bit string types (BYTE, WORD, DWORD, LWORD)");
   constexpr int width = detail::bit_width<T>::value;
   n = n % width;
   return static_cast<T>((static_cast<typename std::make_unsigned<T>::type>(x) >> n) & detail::allBits<T>());
}

// Overload for UInt types (unsigned integers)
template<typename T>
inline T SHR_INT(T x, int n)
{
   static_assert(std::is_unsigned<T>::value, "SHR_INT is only defined for unsigned integer types");
   constexpr int width = sizeof(T) * 8;
   n = n % width;
   if (n >= width) {
      return 0;
   }
   return static_cast<T>(x >> n);
}

// ============================================================================
// Rotate left
// ============================================================================

/**
 * @brief Rotate left
 * 
 * IEC 61131-3: ROL(x, n)
 * Rotates x left by n bits. Bits shifted out on the left are
 * shifted in on the right.
 * For bit strings, the shift count is interpreted modulo the bit width.
 */
template<typename T>
inline T ROL(T x, int n)
{
   static_assert(detail::is_bitstring<T>::value, "ROL is only defined for bit string types (BYTE, WORD, DWORD, LWORD)");
   constexpr int width = detail::bit_width<T>::value;
   n = n % width;
   using U = typename std::make_unsigned<T>::type;
   U ux = static_cast<U>(x);
   U result = (ux << n) | (ux >> (width - n));
   return static_cast<T>(result & detail::allBits<T>());
}

// Overload for UInt types (unsigned integers)
template<typename T>
inline T ROL_INT(T x, int n)
{
   static_assert(std::is_unsigned<T>::value, "ROL_INT is only defined for unsigned integer types");
   constexpr int width = sizeof(T) * 8;
   n = n % width;
   if (n == 0) {
      return x;
   }
   return static_cast<T>((x << n) | (x >> (width - n)));
}

// ============================================================================
// Rotate right
// ============================================================================

/**
 * @brief Rotate right
 * 
 * IEC 61131-3: ROR(x, n)
 * Rotates x right by n bits. Bits shifted out on the right are
 * shifted in on the left.
 * For bit strings, the shift count is interpreted modulo the bit width.
 */
template<typename T>
inline T ROR(T x, int n)
{
   static_assert(detail::is_bitstring<T>::value, "ROR is only defined for bit string types (BYTE, WORD, DWORD, LWORD)");
   constexpr int width = detail::bit_width<T>::value;
   n = n % width;
   using U = typename std::make_unsigned<T>::type;
   U ux = static_cast<U>(x);
   U result = (ux >> n) | (ux << (width - n));
   return static_cast<T>(result & detail::allBits<T>());
}

// Overload for UInt types (unsigned integers)
template<typename T>
inline T ROR_INT(T x, int n)
{
   static_assert(std::is_unsigned<T>::value, "ROR_INT is only defined for unsigned integer types");
   constexpr int width = sizeof(T) * 8;
   n = n % width;
   if (n == 0) {
      return x;
   }
   return static_cast<T>((x >> n) | (x << (width - n)));
}

// ============================================================================
// Selection functions
// ============================================================================

/**
 * @brief Minimum of two values
 * 
 * IEC 61131-3: MIN(x, y)
 * Returns the smaller of x and y.
 */
template<typename T>
inline T MIN(T x, T y)
{
   return x < y ? x : y;
}

/**
 * @brief Minimum of three or more values (variadic)
 * 
 * IEC 61131-3: MIN(x, y, z, ...)
 * Returns the smallest of all arguments.
 */
template<typename T, typename... Args>
inline T MIN(T first, Args... args)
{
   T rest = MIN(args...);
   return first < rest ? first : rest;
}

/**
 * @brief Maximum of two values
 * 
 * IEC 61131-3: MAX(x, y)
 * Returns the larger of x and y.
 */
template<typename T>
inline T MAX(T x, T y)
{
   return x > y ? x : y;
}

/**
 * @brief Maximum of three or more values (variadic)
 * 
 * IEC 61131-3: MAX(x, y, z, ...)
 * Returns the largest of all arguments.
 */
template<typename T, typename... Args>
inline T MAX(T first, Args... args)
{
   T rest = MAX(args...);
   return first > rest ? first : rest;
}

/**
 * @brief Multiplexer
 * 
 * IEC 61131-3: MUX(k, x0, x1, ..., xn)
 * Returns the k-th input (0-indexed). k must be in [0, n].
 * 
 * Note: This is implemented as a variadic template. The first argument
 * is the index, followed by the values to select from.
 */
template<typename T, typename... Args>
inline T MUX(int k, T first, Args... args)
{
   if (k == 0) {
      return first;
   }
   return MUX(k - 1, args...);
}

// Base case for MUX (single value)
template<typename T>
inline T MUX(int k, T value)
{
   // If k is not 0, this is an out-of-range access
   // IEC behavior: undefined, we return the last value
   return value;
}

/**
 * @brief Limit
 * 
 * IEC 61131-3: LIMIT(min, x, max)
 * Returns:
 *   - min if x < min
 *   - max if x > max
 *   - x otherwise
 */
template<typename T>
inline T LIMIT(T min, T x, T max)
{
   if (x < min) {
      return min;
   }
   if (x > max) {
      return max;
   }
   return x;
}

// ============================================================================
// Type checking functions
// ============================================================================

/**
 * @brief Check if a value is NaN (Not a Number)
 * 
 * IEC 61131-3: IS_NAN(x)
 * Returns true if x is NaN, false otherwise.
 */
template<typename T>
inline BOOL IS_NAN(T x)
{
   static_assert(detail::is_float<T>::value || std::is_same<T, LREAL>::value, "IS_NAN is only defined for floating point types");
   return std::isnan(x) ? true : false;
}

inline BOOL IS_NAN(LREAL x)
{
   return std::isnan(x) ? true : false;
}

/**
 * @brief Check if a value is infinite
 * 
 * IEC 61131-3: IS_INFINITE(x)
 * Returns true if x is infinite, false otherwise.
 */
template<typename T>
inline BOOL IS_INFINITE(T x)
{
   static_assert(detail::is_float<T>::value || std::is_same<T, LREAL>::value, "IS_INFINITE is only defined for floating point types");
   return std::isinf(x) ? true : false;
}

inline BOOL IS_INFINITE(LREAL x)
{
   return std::isinf(x) ? true : false;
}

// ============================================================================
// Additional bit operations
// ============================================================================

/**
 * @brief Bitwise NOT (complement)
 * 
 * Returns the bitwise complement of x (all bits inverted).
 */
template<typename T>
inline T NOT(T x)
{
   static_assert(detail::is_bitstring<T>::value || std::is_integral<T>::value, "NOT is only defined for bit string and integral types");
   return static_cast<T>(~static_cast<typename std::make_unsigned<T>::type>(x) & detail::allBits<T>());
}

/**
 * @brief Bitwise AND
 * 
 * Returns the bitwise AND of x and y.
 */
template<typename T>
inline T AND(T x, T y)
{
   static_assert(detail::is_bitstring<T>::value || std::is_integral<T>::value, "AND is only defined for bit string and integral types");
   return static_cast<T>(static_cast<typename std::make_unsigned<T>::type>(x) & static_cast<typename std::make_unsigned<T>::type>(y));
}

/**
 * @brief Bitwise OR
 * 
 * Returns the bitwise OR of x and y.
 */
template<typename T>
inline T OR(T x, T y)
{
   static_assert(detail::is_bitstring<T>::value || std::is_integral<T>::value, "OR is only defined for bit string and integral types");
   return static_cast<T>(static_cast<typename std::make_unsigned<T>::type>(x) | static_cast<typename std::make_unsigned<T>::type>(y));
}

/**
 * @brief Bitwise XOR
 * 
 * Returns the bitwise XOR of x and y.
 */
template<typename T>
inline T XOR(T x, T y)
{
   static_assert(detail::is_bitstring<T>::value || std::is_integral<T>::value, "XOR is only defined for bit string and integral types");
   return static_cast<T>(static_cast<typename std::make_unsigned<T>::type>(x) ^ static_cast<typename std::make_unsigned<T>::type>(y));
}

// ============================================================================
// Integer division and modulo (with proper handling of negative values)
// ============================================================================

/**
 * @brief Integer division (truncate toward zero)
 * 
 * IEC 61131-3: DIV(x, y)
 * Returns the quotient of x divided by y, truncated toward zero.
 */
template<typename T>
inline T DIV(T x, T y)
{
   static_assert(std::is_integral<T>::value, "DIV is only defined for integral types");
   if constexpr (std::is_signed<T>::value) {
      return static_cast<T>(std::trunc(static_cast<LREAL>(x) / static_cast<LREAL>(y)));
   } else {
      return static_cast<T>(x / y);
   }
}

/**
 * @brief Integer modulo (remainder, same sign as dividend)
 * 
 * IEC 61131-3: MOD(x, y)
 * Returns the remainder of x divided by y.
 * The result has the same sign as x (dividend).
 */
template<typename T>
inline T MOD(T x, T y)
{
   static_assert(std::is_integral<T>::value, "MOD is only defined for integral types");
   if constexpr (std::is_signed<T>::value) {
      // For signed integers, result has same sign as x
      T quotient = static_cast<T>(std::trunc(static_cast<LREAL>(x) / static_cast<LREAL>(y)));
      return static_cast<T>(x - quotient * y);
   } else {
      return static_cast<T>(x % y);
   }
}

// ============================================================================
// Aliases for commonly used functions
// ============================================================================

// Short aliases for bit operations (for convenience in generated code)
using SHL = SHL;
using SHR = SHR;
using ROL = ROL;
using ROR = ROR;

